/**
 * Format a date for display
 */
function formatDate(dateStr) {
  if (!dateStr) return '--';
  try {
    const d = new Date(dateStr);
    return d.toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });
  } catch(e) { return dateStr; }
}

/**
 * Format a timestamp for display
 */
function formatTime(ts) {
  if (!ts) return '--';
  try {
    return new Date(ts).toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' });
  } catch(e) { return '--'; }
}

/**
 * Format currency (IDR)
 */
function formatCurrency(amount, currency) {
  currency = currency || 'IDR';
  if (amount === null || amount === undefined || amount === '--') return '--';
  try {
    return new Intl.NumberFormat('id-ID', { style: 'currency', currency: currency, maximumFractionDigits: 0 }).format(amount);
  } catch(e) { return amount; }
}

/**
 * Debounce function
 */
function debounce(fn, ms) {
  let timer;
  return function() {
    clearTimeout(timer);
    timer = setTimeout(() => fn.apply(this, arguments), ms || 300);
  };
}

/**
 * Safe JSON parse
 */
function safeParse(str, fallback) {
  try { return JSON.parse(str); }
  catch(e) { return fallback || null; }
}

/**
 * Toast notification
 */
function showToast(message, type, duration) {
  type = type || 'info';
  duration = duration || 3000;
  const toast = document.getElementById('toast') || document.createElement('div');
  toast.className = 'toast ' + type + ' show';
  toast.textContent = message;
  setTimeout(() => { toast.classList.remove('show'); }, duration);
}

/**
 * Escape HTML
 */
function escapeHtml(str) {
  if (!str) return '';
  return String(str).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

/**
 * CSRF token fetch helper
 */
async function fetchWithCsrf(url, opts) {
  opts = opts || {};
  if (!opts.headers) opts.headers = {};
  if (typeof window._csrfToken === 'string' && window._csrfToken) {
    opts.headers['x-csrf-token'] = window._csrfToken;
  }
  return fetch(url, opts);
}

